import axios from 'axios';

const API_BASE_URL = 'http://localhost:5000/product-types';
const PRODUCTS_API_BASE_URL = 'http://localhost:5000/products';

export const getProductTypes = () => axios.get(API_BASE_URL);
export const getProductType = (id) => axios.get(`${API_BASE_URL}/${id}`);
export const createProductType = (data) => axios.post(API_BASE_URL, data);
export const updateProductType = (id, data) => axios.put(`${API_BASE_URL}/${id}`, data);
export const deleteProductType = (id) => axios.delete(`${API_BASE_URL}/${id}`);

// Product APIs
export const getProducts = () => axios.get(PRODUCTS_API_BASE_URL);
export const getProduct = (id) => axios.get(`${PRODUCTS_API_BASE_URL}/${id}`);
export const createProduct = (data) => axios.post(PRODUCTS_API_BASE_URL, data);
export const updateProduct = (id, data) => axios.put(`${PRODUCTS_API_BASE_URL}/${id}`, data);
export const deleteProduct = (id) => axios.delete(`${PRODUCTS_API_BASE_URL}/${id}`);
